var e=JSON.parse(`[{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"관리국 연합 전대 작전 <color=#ffd34c>커튼콜</color>\\n작전 개시 3시간 전","JPN":"管理局連合戦隊作戦<color=#ffd34c>カーテンコール</color>\\n作戦開始3時間前","ENG":"[[","TWN":"管理局聯合戰隊作戰<color=#ffd34c>謝幕</color>\\n作戰開始前3小時","SCN":"管理局联合战队作战<color=#ffd34c>谢幕</color>\\n作战开始前3小时","DEU":"[[","FRA":"[["},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"TOMB","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"……그게 무슨 소리야?","JPN":"……どういうことだ？","ENG":"...What are you talking about?","TWN":"……那是什麼意思？"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"우린 네가 그 화재에서 카운터로 각성한다는 걸 알고 있었어.","JPN":"私たちはあの火災現場であなたがカウンターとして覚醒することを知っていた。","ENG":"We knew you'd awaken as a Counter in that fire.","TWN":"我們知道你會在這場大火中覺醒，成為制裁者。"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"물론, 카운터의 각성은 필연적이라 그걸 바꾸면 무슨 일이 발생할지 모르지만…….","JPN":"もちろん、カウンターの覚醒は必然のことだから……それを変えてしまったら何が起こるかわからないけど……","ENG":"Of course, a Counter's awakening is inevitable, so we don't know what would've happened if it changed...","TWN":"制裁者的覺醒不可避免，如果發生改變，不知道會發生什麼事情……"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"그래, 더는 변명하지는 않을게.","JPN":"そうね、これ以上の言い訳はやめるよ。","ENG":"but I won't make any more excuses.","TWN":"好吧，我不會再找任何藉口了。"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"네가 관리국에…… 그리고 야크샤에게 반드시 필요한 사람이었기 때문이었어.","JPN":"あなたが管理局に……そしてヤクシャーに必ず必要な人間だったからよ。","ENG":"It was because... you were someone the Administration and Yaksha needed.","TWN":"你對於管理局……對於夜叉來說，都是不可缺少的存在。"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"그래서 우린 그 화재에서 너를 선택한 거야.","JPN":"だから私たちは、あの火災であなたを選択したの。","ENG":"That's why we chose you in that fire.","TWN":"這就是為什麼我們在那場大火中選擇了你。"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"그게 우리의 최선이었어.","JPN":"それが私たちにとっての最善だった。","ENG":"That was our best outcome.","TWN":"那是我們最好的結果。"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"최선, 최선……!! 그딴 개소리 집어 치워!!","JPN":"最善、最善って、いいかげんにしろ！！","ENG":"Stop saying that word, \\"best!\\"","TWN":"最好的，最好的……！！別說那些屁話！"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_HATE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"내 어딜 보고 최선이었다는 거야!!","JPN":"アタシの何が最善なんだ！！","ENG":"How was I the best outcome?!","TWN":"我哪裡看起來是最好的了！！"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"이 망할 귀랑 꼬리 때문이야!? 아니면 내가 환상종 인자를 물려받았기 때문이야!?","JPN":"このくそ耳と尻尾のせいか！？　アタシが幻想種の因子を受け継いでいるから！？","ENG":"Because of these stupid ears and tail?! Or because I carry the Bygone Factor?!","TWN":"是因為這該死的耳朵和尾巴嗎？！還是因為我繼承了夢幻品種因子？！"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"그게 대장님과 동료들……! 그 아이가 죽어야만 했던 이유냐고……!?","JPN":"隊長と仲間たち……あの子が死ななければならなかった理由になるのかよ！？","ENG":"Was that enough of a reason...! To kill Captain, my colleagues, and that kid...?!","TWN":"隊長，還有同伴……！還有那個孩子為什麼必須死……？！"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_HATE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"대답해!! 주디 스위프트!!","JPN":"答えろ、ジュディ・スウィフト！！","ENG":"Answer my question!! Judy Swift!!","TWN":"回答我！！茱蒂·斯威福特！！"},"stage":{"bg":"OFFICE_TOP","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SERIOUS"}}}},{"id":"L24_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"관리국이……!! 너희가 나한테 바라는 게 대체 뭐야……!?","JPN":"管理局は……！！　おまえらはアタシに何を求めている……！？","ENG":"What does the Administration...!! Or you want from me...?!","TWN":"管理局……！！到底想從我這裡得到什麼……？！"},"stage":{"bg":"OFFICE_TOP","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_HATE"}}}},{"id":"L25_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"OFFICE_TOP","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_HATE"}}}},{"id":"L27_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"야크샤의 우두머리.","JPN":"ヤクシャーのリーダー。","ENG":"The head of Yaksha.","TWN":"夜叉的領袖。"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"뭐……?","JPN":"は……？","ENG":"What...?","TWN":"什麼……？"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"관리국은 널 야크샤의 전대장으로 추천했어.","JPN":"管理局はあなたをヤクシャーの戦隊長として推奨した。","ENG":"The Administration recommended you as the Commander of the Yaksha Division.","TWN":"管理局推薦你當夜叉戰隊長。"},"stage":{"bg":"OFFICE_TOP","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SURPRISE"}}}},{"id":"L32_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"우리는 거기에 동의했고. 그게 그 화재에서 우리가 널 구한 이유야.","JPN":"そして私たちはそれに同意した。それがあの火災であなたを助けた理由よ。","ENG":"And we agreed to it. That's why we saved you in that fire.","TWN":"我們同意了。這就是我們把你從火災中救出來的原因。"},"stage":{"bg":"OFFICE_TOP","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SURPRISE"}}}},{"id":"L34_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"그게 무슨 소리야……?","JPN":"どういうことだ……？","ENG":"What are you saying...?","TWN":"你在說什麼……？"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"내가 왜 야크샤의 전대장이 되어야 한다는 거야? 라이오넬 전대장은?","JPN":"なぜアタシがヤクシャーの戦隊長にならなきゃいけないんだ……？　ライオネル戦隊長は？","ENG":"Why am I supposed to be the Yaksha's Commander? What about Commander Lionel?","TWN":"為什麼一定要我成為夜叉的戰隊長？萊諾戰隊長呢？"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_HATE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"야크샤는 줄곧 라이오넬 전대장을 찾고 있었다면서!","JPN":"ヤクシャーはずっとライオネル戦隊長を探しているんだろ！","ENG":"You told me that Yaksha's been searching for Commander Lionel all this time!","TWN":"夜叉不是一直在尋找萊諾戰隊長嗎！"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"……자세한 이유는 우리도 몰라.","JPN":"……詳しいことは私たちにもわからない。","ENG":"...We also don't know the exact details.","TWN":"……我們不知道具體的原因。"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};